function clean(value) {
  return String(value ?? '').trim();
}

function slug(value, max = 24) {
  return clean(value)
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, max);
}

function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(36);
}

function todayLocalYmd() {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

const payload = Array.isArray(items[0]?.json?.body) ? items[0].json.body : [];

return payload
  .filter((row) => clean(row?.['Company']) && clean(row?.['Job Title']))
  .map((row) => {
    const newRow = { ...row };

    const existingDateScraped = clean(newRow['Date Scraped']);
    if (!existingDateScraped) {
      newRow['Date Scraped'] = todayLocalYmd();
    }

    const existingJobRef = clean(newRow['Job Ref']);
    if (existingJobRef.startsWith('lead-')) {
      return { json: newRow };
    }

    const title = clean(newRow['Job Title']);
    const company = clean(newRow['Company']);
    const location = clean(newRow['Location']);
    const country = clean(newRow['Country']);
    const jobUrl = clean(newRow['Job URL']);
    const datePosted = clean(newRow['Date Posted']);
    const platform = clean(newRow['Platform']);

    const fingerprint = [
      jobUrl,
      company,
      title,
      location,
      country,
      datePosted,
      platform
    ].join('|');

    const companyPart = slug(company || 'company');
    const titlePart = slug(title || 'role');
    const hashPart = hashString(fingerprint);

    newRow['Job Ref'] = `lead-${companyPart}-${titlePart}-${hashPart}`;

    return { json: newRow };
  });

function normalise(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

function splitList(value) {
  return String(value || '')
    .split(/[\n|,]+/g)
    .map(v => normalise(v))
    .filter(Boolean);
}

const loopUser = items[0]?.json || {};
const bundledLeadItem = $items("Bundle valid leads1", 0, 0)[0]?.json || {};
const leadItems = Array.isArray(bundledLeadItem.leads) ? bundledLeadItem.leads : [];

const resolvedUserKey =
  loopUser.userKey ||
  loopUser['userKey '] ||
  loopUser['UserKey'] ||
  loopUser['userkey'] ||
  loopUser['user key'] ||
  '';

const resolvedLeadChatId = loopUser.leadChatId || '';
const resolvedOutputChatId = loopUser.outputChatId || '';
const resolvedCustomPrompt = loopUser.customPrompt || '';
const resolvedUserName = loopUser.name || loopUser.userName || '';

// User preferences from sheet columns
const allowedCategories = splitList(loopUser.category || '');
const allowedSubSpecialisms = splitList(loopUser.subSpecialism || '');
const allowedCountries = splitList(loopUser.country || '');

const meta = {
  userKey: resolvedUserKey,
  leadChatId: resolvedLeadChatId,
  outputChatId: resolvedOutputChatId,
  customPrompt: resolvedCustomPrompt,
  userName: resolvedUserName,
};

const matched = leadItems.filter(row => {
  // Category filter
  if (allowedCategories.length > 0) {
    const leadCategories = splitList(row['Category'] || '');
    if (!leadCategories.some(v => allowedCategories.includes(v))) {
      return false;
    }
  }

  // Sub-specialism filter — only match against Sub Specialism, never fall back to Category
  if (allowedSubSpecialisms.length > 0) {
    const leadSubSpecList = splitList(row['Sub Specialism'] || '');
    if (!leadSubSpecList.some(v => allowedSubSpecialisms.includes(v))) {
      return false;
    }
  }

  // Country filter
  if (allowedCountries.length > 0) {
    const leadCountry = normalise(row['Country'] || '');
    if (!allowedCountries.some(c => leadCountry === c || leadCountry.includes(c) || c.includes(leadCountry))) {
      return false;
    }
  }

  return true;
});

// Always return at least one item so the loop continues to the next user.
// __skip signals Build HTML to suppress the Teams send for this user.
if (matched.length === 0) {
  return [{ json: { ...meta, __skip: true } }];
}

return matched.map(row => ({ json: { ...row, ...meta } }));

const selectionWebhookBase = 'https://antonyberou.app.n8n.cloud/webhook/job-lead-queue';

function esc(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\\"/g, '&quot;');
}

function displayValue(value) {
  const cleaned = String(value ?? '').trim();
  return cleaned || 'Unknown';
}

const first = items[0]?.json || {};
const leadChatId = String(first.leadChatId || '').trim();
const outputChatId = String(first.outputChatId || '').trim();
const userKey = String(first.userKey || '').trim();
const userName = String(first.userName || '').trim();

// No leads matched for this user — return an item with empty leadChatId so
// the Teams node fails silently (it has onError: continueRegularOutput) and
// the loop proceeds to the next user without sending anything.
if (first.__skip) {
  return [{ json: { jobsHtml: '', leadChatId: '', outputChatId, userKey, userName, __skip: true } }];
}

const rowsHtml = items.map((item) => {
  const row = item.json;

  const company = displayValue(row['Company']);
  const jobTitle = displayValue(row['Job Title']);
  const location = displayValue(row['Location']);
  const country = displayValue(row['Country']);
  const salary = displayValue(row['Salary']);
  const platform = displayValue(row['Platform']);
  const category = displayValue(row['Category']);
  const subSpecialism = displayValue(row['Sub Specialism']);
  const contractType = displayValue(row['Contract Type']);
  const datePosted = displayValue(row['Date Posted']);
  const jobUrl = String(row['Job URL'] || '').trim();
  const jobRef = String(row['Job Ref'] || '').trim();

  const createOutreachUrl = `${selectionWebhookBase}?jobRef=${encodeURIComponent(jobRef)}&userKey=${encodeURIComponent(userKey)}`;

  return `
    <div style="font-family: Arial, sans-serif; font-size: 14px; line-height: 1.5; margin: 0 0 16px 0;">
      <div><strong>Company:</strong> ${esc(company)}</div>
      <div><strong>Title:</strong> ${esc(jobTitle)}</div>
      <div><strong>Location:</strong> ${esc(location)}, ${esc(country)}</div>
      <div><strong>Date Posted:</strong> ${esc(datePosted)}</div>
      <div><strong>Category:</strong> ${esc(category)} - ${esc(subSpecialism)}</div>
      <div><strong>Salary:</strong> ${esc(salary)}</div>
      <div><strong>Contract:</strong> ${esc(contractType)}</div>
      <div><strong>Platform:</strong> ${esc(platform)}</div>
      <div style="margin-top: 8px;">
        <a href="${createOutreachUrl}">Create Outreach</a>
        ${jobUrl ? ` | <a href="${esc(jobUrl)}">Open advert</a>` : ''}
      </div>
    </div>
    <hr style="border: 0; border-top: 1px solid #cccccc; margin: 12px 0;">
  `;
}).join('');

return [{
  json: {
    jobsHtml: rowsHtml,
    leadChatId,
    outputChatId,
    userKey,
    userName
  }
}];
